{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select the source volume",
      "simple": "Choose the volume that contains the skull for segmentation.",
      "detailed": "This is the starting point — you will segment the skull from this volume to later plan the implant. Pick the appropriate CT or MRI scan from the list."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create a new segmentation",
      "simple": "Create a segmentation named 'Cranial_Segmentation'.",
      "detailed": "A segmentation will hold the skull mask and later the implant. Name it clearly so you can identify it later in the workflow."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add and name a segment",
      "simple": "Click 'Add' and rename the segment to 'Cranial_Segment'.",
      "detailed": "This segment will store the skull mask. Renaming it helps you keep track of which segment represents the skull versus the implant."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open the Threshold tool",
      "simple": "Click the 'Threshold' button.",
      "detailed": "Thresholding uses Hounsfield units (or pixel values) to isolate bone. Since you are working with a skull, bone will appear bright. You will adjust the range next."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set the threshold range",
      "simple": "Adjust the threshold bar to capture the skull bone.",
      "detailed": "Move the range sliders until only the skull is highlighted — this isolates the bone from soft tissue and air. The exact range depends on your scan, but bone typically sits above 200–300 HU for CT."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply the threshold",
      "simple": "Click 'Apply' to create the skull segment.",
      "detailed": "This fills the 'Cranial_Segment' with the voxels within your chosen threshold range, producing a rough skull mask. You will refine it later with the ROI."
    },
    {
      "step_id": "cb_step_7",
      "title": "Select the skull mask segment",
      "simple": "Choose the 'Cranial_Segment' from the skull mask list.",
      "detailed": "The extension needs to know which segment is the skull mask to load it for further processing. Pick the one you just created."
    },
    {
      "step_id": "cb_step_8",
      "title": "Load the skull mask",
      "simple": "Click 'Load Skull Mask'.",
      "detailed": "This converts your segmentation into a working model that the extension can crop and cut. Wait until it finishes before proceeding."
    },
    {
      "step_id": "cb_step_9",
      "title": "Add a region of interest",
      "simple": "Click 'Add ROI' to create a box around the skull.",
      "detailed": "The ROI (region of interest) defines the area you want to keep. You will adjust it next to isolate only the skull portion that contains the defect."
    },
    {
      "step_id": "cb_step_10",
      "title": "Adjust the ROI boundaries",
      "simple": "Drag the handles to enclose the skull portion you want to keep.",
      "detailed": "Position the ROI tightly around the skull area that includes the defect. This removes irrelevant anatomy and speeds up calculations. Make sure the defect is fully inside the box."
    },
    {
      "step_id": "cb_step_11",
      "title": "Crop the skull to the ROI",
      "simple": "Click 'Crop to ROI'.",
      "detailed": "This cuts the skull mask down to only the region inside your ROI, discarding everything outside. The cropped mask will be used for the cutting step."
    },
    {
      "step_id": "cb_step_12",
      "title": "Adjust the 3D view",
      "simple": "Rotate and zoom to see the skull defect clearly.",
      "detailed": "A good view is essential for drawing the cutting curve accurately. Position the camera so you can see the entire defect boundary and surrounding bone."
    },
    {
      "step_id": "cb_step_13",
      "title": "Create a closed curve",
      "simple": "Select 'Closed Curve' from the Markups toolbar.",
      "detailed": "This creates a closed curve that you will place around the defect. It will serve as the cutting guide for separating the defective bone from healthy bone."
    },
    {
      "step_id": "cb_step_14",
      "title": "Draw the cutting curve",
      "simple": "Place points along the edge of the skull defect to outline it.",
      "detailed": "Click on the skull surface to define the boundary between healthy bone and the defect. Place points at regular intervals around the entire defect. The curve must fully enclose the defect. Once you are done, click 'Done'."
    },
    {
      "step_id": "cb_step_15",
      "title": "Select the curve",
      "simple": "Choose the curve you just drew from the list.",
      "detailed": "The extension uses this curve to know exactly where to cut. Pick the one you created in the previous step."
    },
    {
      "step_id": "cb_step_16",
      "title": "Cut the defect",
      "simple": "Click 'Cut Defect'.",
      "detailed": "This removes the portion of the skull inside the curve, creating a clean defect model. The extension will use this to generate the implant shape. Wait for completion."
    },
    {
      "step_id": "cb_step_17",
      "title": "Hide the curve",
      "simple": "Make the curve invisible.",
      "detailed": "Hiding the curve cleans up the view so you can focus on the defect and the upcoming implant generation."
    },
    {
      "step_id": "cb_step_18",
      "title": "Generate the implant",
      "simple": "Click 'Generate Implant' to create the cranial implant.",
      "detailed": "The extension automatically creates a custom implant that fits the defect. It will appear as a new segmentation. Review it in the 3D view and prepare for surgical use."
    }
  ]
}
